/**
 * @name Command injection via subprocess
 * @description Using subprocess with user-controlled input without proper sanitization can lead to command injection
 * @kind path-problem
 * @problem.severity error
 * @id py/command-injection
 * @tags security
 *        external/cwe/cwe-078
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module CommandInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(SystemCommandExecution cmd |
      sink = cmd.getCommand()
    )
  }
}

module CommandInjectionFlow = TaintTracking::Global<CommandInjectionConfig>;
import CommandInjectionFlow::PathGraph

from CommandInjectionFlow::PathNode source, CommandInjectionFlow::PathNode sink
where CommandInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Command injection from $@.", source.getNode(), "user input"

/**
 * @name Path traversal in file operations
 * @description Using unsanitized user input in file operations can allow path traversal attacks
 * @kind path-problem
 * @problem.severity error
 * @id py/path-traversal
 * @tags security
 *        external/cwe/cwe-022
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(FileSystemAccess fa |
      sink = fa.getAPathArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal from $@.", source.getNode(), "user input"
